sql:
SELECT usage_type_name
FROM usage_types
WHERE is_active = 1;

SELECT COUNT(*) AS active_usage_count
FROM product_usage
WHERE usage_type_id = 1 AND is_active = 1;

SELECT SUM(quantity_used) AS total_quantity_used
FROM product_usage
WHERE package_id = 1 AND usage_date BETWEEN '2023-05-01' AND '2023-05-31';

external_knowledge:
- "most abundant" refers to having the highest quantity in stock;
- "active products" means products that are currently available and not discontinued;
- "minimum required stock" refers to the minimum stock level for the product;
- locations "not full" means locations with available capacity;
- excluding "recalled packages" means packages that have not been recalled due to defects or safety concerns.

